from django.contrib.auth import login
from django.shortcuts import redirect
from saml2.saml2 import Saml2Assertion
from saml2.xmlparser import BeautifulSoup
from django.contrib.auth.models import User
from django.core.exceptions import ValidationError

def saml_post_response(request):
    if request.method == 'POST':
        # Parse SAML XML response
        xml_response = BeautifulSoup(request.body, 'xml')
        saml_assertion = Saml2Assertion(xml_response.find('Assertion'))

        # Extract user information from assertion attributes
        name_id = saml_assertion.name_id.text
        attributes = saml_assertion.attributes

        # Validate XML structure
        try:
            saml_assertion.validate()
        except ValidationError as e:
            return redirect('error_page')

        # Create or retrieve user based on NameID
        user, _ = User.objects.get_or_create(username=name_id)

        # Set user attributes
        for attribute in attributes:
            user.set_attribute(attribute.friendly_name, attribute.text)

        # Log in user and set session
        login(request, user)

        return redirect('portal_home')

    return redirect('error_page')